def _extract_block(plane: list[list[int]], block_row: int, block_col: int) -> list[list[float]]:
    block = [[0.0 for _ in range(8)] for _ in range(8)]
    for row in range(8):
        for col in range(8):
            block[row][col] = float(plane[block_row * 8 + row][block_col * 8 + col] - 128)
    return block

