def _write_marker(buffer: bytearray, marker: int, payload: bytes = b"") -> None:
    buffer.extend(struct.pack(">H", marker))
    if payload:
        buffer.extend(struct.pack(">H", len(payload) + 2))
        buffer.extend(payload)
